import{_ as a,o,c as i,ag as l}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"qr","description":"`openclaw qr`에 대한 CLI 참조 (모바일 페어링 QR + 설정 코드 생성)","frontmatter":{"title":"qr","description":"`openclaw qr`에 대한 CLI 참조 (모바일 페어링 QR + 설정 코드 생성)"},"headers":[],"relativePath":"cli/qr.md","filePath":"cli/qr.md","lastUpdated":null}'),s={name:"cli/qr.md"};function t(c,e,d,r,n,p){return o(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="openclaw-qr" tabindex="-1"><code>openclaw qr</code> <a class="header-anchor" href="#openclaw-qr" aria-label="Permalink to &quot;\`openclaw qr\`&quot;">​</a></h1><p>현재 Gateway 구성에서 모바일 페어링 QR 및 설정 코드를 생성합니다.</p><h2 id="사용법" tabindex="-1">사용법 <a class="header-anchor" href="#사용법" aria-label="Permalink to &quot;사용법&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qr</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --setup-code-only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --remote</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wss://gateway.example/ws</span></span></code></pre></div><h2 id="옵션" tabindex="-1">옵션 <a class="header-anchor" href="#옵션" aria-label="Permalink to &quot;옵션&quot;">​</a></h2><ul><li><code>--remote</code>: <code>gateway.remote.url</code>을 선호합니다; 설정되지 않은 경우 <code>gateway.tailscale.mode=serve|funnel</code>이 여전히 원격 공개 URL을 제공할 수 있습니다</li><li><code>--url &amp;lt;url&amp;gt;</code>: 페이로드에서 사용되는 게이트웨이 URL 재정의</li><li><code>--public-url &amp;lt;url&amp;gt;</code>: 페이로드에서 사용되는 공개 URL 재정의</li><li><code>--token &amp;lt;token&amp;gt;</code>: 부트스트랩 흐름이 인증하는 게이트웨이 토큰 재정의</li><li><code>--password &amp;lt;password&amp;gt;</code>: 부트스트랩 흐름이 인증하는 게이트웨이 비밀번호 재정의</li><li><code>--setup-code-only</code>: 설정 코드만 출력</li><li><code>--no-ascii</code>: ASCII QR 렌더링 건너뜀</li><li><code>--json</code>: JSON 출력 (<code>setupCode</code>, <code>gatewayUrl</code>, <code>auth</code>, <code>urlSource</code>)</li></ul><h2 id="참고사항" tabindex="-1">참고사항 <a class="header-anchor" href="#참고사항" aria-label="Permalink to &quot;참고사항&quot;">​</a></h2><ul><li><code>--token</code>과 <code>--password</code>는 상호 배타적입니다.</li><li>설정 코드 자체는 이제 공유된 게이트웨이 토큰/비밀번호가 아닌 불투명한 단기 <code>bootstrapToken</code>을 포함합니다.</li><li>내장 노드/운영자 부트스트랩 흐름에서 기본 노드 토큰은 여전히 <code>scopes: []</code>로 제공됩니다.</li><li>부트스트랩 핸드오프가 운영자 토큰도 발행하는 경우 부트스트랩 허용 목록으로 제한됩니다: <code>operator.approvals</code>, <code>operator.read</code>, <code>operator.talk.secrets</code>, <code>operator.write</code>.</li><li>부트스트랩 범위 확인은 역할이 접두사로 붙습니다. 해당 운영자 허용 목록은 운영자 요청만 충족시킵니다; 비운영자 역할은 여전히 자신의 역할 접두사 아래에서 범위가 필요합니다.</li><li>모바일 페어링은 Tailscale/공개 <code>ws://</code> 게이트웨이 URL에 대해 실패합니다. 사설 LAN <code>ws://</code>는 계속 지원되지만 Tailscale/공개 모바일 경로는 Tailscale Serve/Funnel 또는 <code>wss://</code> 게이트웨이 URL을 사용해야 합니다.</li><li><code>--remote</code>를 사용하면 OpenClaw는 <code>gateway.remote.url</code> 또는 <code>gateway.tailscale.mode=serve|funnel</code>이 필요합니다.</li><li><code>--remote</code>를 사용하면 활성화된 원격 자격 증명이 SecretRef로 구성되고 <code>--token</code> 또는 <code>--password</code>를 전달하지 않으면 명령이 활성 게이트웨이 스냅샷에서 이를 확인합니다. 게이트웨이를 사용할 수 없으면 명령이 빠르게 실패합니다.</li><li><code>--remote</code> 없이 CLI 인증 재정의가 전달되지 않으면 로컬 게이트웨이 인증 SecretRef가 확인됩니다: <ul><li><code>gateway.auth.token</code>은 토큰 인증이 이길 수 있을 때 확인됩니다 (명시적 <code>gateway.auth.mode=&quot;token&quot;</code> 또는 비밀번호 소스가 이기지 않는 추론된 모드).</li><li><code>gateway.auth.password</code>는 비밀번호 인증이 이길 수 있을 때 확인됩니다 (명시적 <code>gateway.auth.mode=&quot;password&quot;</code> 또는 인증/환경에서 이기는 토큰이 없는 추론된 모드).</li></ul></li><li><code>gateway.auth.token</code>과 <code>gateway.auth.password</code> (SecretRef 포함)가 모두 구성되고 <code>gateway.auth.mode</code>가 설정되지 않은 경우 모드가 명시적으로 설정될 때까지 설정 코드 확인이 실패합니다.</li><li>게이트웨이 버전 불일치 참고: 이 명령 경로는 <code>secrets.resolve</code>를 지원하는 게이트웨이가 필요합니다; 이전 게이트웨이는 알 수 없는 메서드 오류를 반환합니다.</li><li>스캔 후 다음을 통해 디바이스 페어링을 승인하세요: <ul><li><code>openclaw devices list</code></li><li><code>openclaw devices approve &amp;lt;requestId&amp;gt;</code></li></ul></li></ul>`,8)])])}const u=a(s,[["render",t]]);export{k as __pageData,u as default};
